const{Client:Client,GatewayIntentBits:GatewayIntentBits,Events:Events}=require("discord.js"),config=require("./config"),CommandManager=require("./services/commandManager");async function testDiscordBot(){try{console.log("🤖 Testing Discord Bot with Slash Commands..."),console.log("=".repeat(50));const client=new Client({intents:[GatewayIntentBits.Guilds,GatewayIntentBits.GuildMessages]}),commandManager=new CommandManager;client.once("ready",(async()=>{console.log(`✅ Discord bot logged in as ${client.user.tag}`);try{console.log("🔧 Registering slash commands...");const commands=commandManager.getCommands(),result=await client.application.commands.set(commands);console.log(`✅ Successfully registered ${result.size} slash commands:`),result.forEach((command=>{console.log(`   /${command.name}: ${command.description}`)})),console.log("\n🎉 Bot is ready! You can now use /collection command in Discord."),console.log("💡 Keep this terminal open to keep the bot running."),console.log("🛑 Press Ctrl+C to stop the bot.")}catch(error){console.error("❌ Failed to register slash commands:",error)}})),client.on(Events.InteractionCreate,(async interaction=>{if(interaction.isChatInputCommand())try{await commandManager.executeCommand(interaction)}catch(error){console.error("❌ Error handling interaction:",error)}})),client.on("error",(error=>{console.error("❌ Discord bot error:",error)})),console.log("🔗 Connecting to Discord..."),await client.login(config.discord.botToken)}catch(error){console.error("❌ Error starting Discord bot:",error),process.exit(1)}}process.on("SIGINT",(async()=>{console.log("\n🛑 Shutting down Discord Bot..."),process.exit(0)})),process.on("SIGTERM",(async()=>{console.log("\n🛑 Shutting down Discord Bot..."),process.exit(0)})),testDiscordBot();